package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.lang.reflect.Field;
import java.util.List;

import org.eclipse.rdf4j.sail.lmdb.LmdbCountingBloomStore.Filter;
import org.eclipse.rdf4j.sail.lmdb.TxnManager.Txn;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class LmdbCountingBloomStoreTest {

	private static final long RDF_TYPE_ID = 100;
	private static final long PERSON_ID = 101;

	private File dataDir;
	private TripleStore tripleStore;

	@BeforeEach
	void setUp(@TempDir File dataDir) throws Exception {
		this.dataDir = dataDir;
		LmdbStoreConfig config = new LmdbStoreConfig("spoc,posc")
				.setBloomFilterExpectedElementsPerFilter(1024)
				.setBloomFilterPartitionCounters(1024);
		tripleStore = new TripleStore(dataDir, config, null);
		tripleStore.setRdfTypeId(RDF_TYPE_ID);
	}

	@AfterEach
	void tearDown() throws Exception {
		tripleStore.close();
	}

	@Test
	void predicateSubjectAndObjectFiltersFollowCommitAndRollback() throws Exception {
		Filter predSubject = Filter.predicateSubject(true, 2);
		Filter predObject = Filter.predicateObject(true, 2);

		tripleStore.startTransaction();
		tripleStore.storeTriple(1, 2, 3, 0, true);
		tripleStore.commit();

		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			assertThat(tripleStore.mightMatchBloom(txn, List.of(List.of(predSubject)), 1)).isTrue();
			assertThat(tripleStore.mightMatchBloom(txn, List.of(List.of(predObject)), 3)).isTrue();
			assertThat(tripleStore.mightMatchBloom(txn, List.of(List.of(predSubject)), 99)).isFalse();
		}

		tripleStore.startTransaction();
		tripleStore.removeTriplesByContext(1, 2, 3, 0, true, ignored -> {
		});
		tripleStore.rollback();

		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			assertThat(tripleStore.mightMatchBloom(txn, List.of(List.of(predSubject)), 1)).isTrue();
			assertThat(tripleStore.mightMatchBloom(txn, List.of(List.of(predObject)), 3)).isTrue();
		}
	}

	@Test
	void explicitAndInferredFiltersAreSeparate() throws Exception {
		Filter explicitSubject = Filter.predicateSubject(true, 2);
		Filter inferredSubject = Filter.predicateSubject(false, 2);

		tripleStore.startTransaction();
		tripleStore.storeTriple(1, 2, 3, 0, false);
		tripleStore.commit();

		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			assertThat(tripleStore.mightMatchBloom(txn, List.of(List.of(inferredSubject)), 1)).isTrue();
			assertThat(tripleStore.mightMatchBloom(txn, List.of(List.of(explicitSubject)), 1)).isFalse();
		}
	}

	@Test
	void duplicateContextQuadsKeepMembershipUntilLastDelete() throws Exception {
		Filter predSubject = Filter.predicateSubject(true, 2);

		tripleStore.startTransaction();
		tripleStore.storeTriple(1, 2, 3, 10, true);
		tripleStore.storeTriple(1, 2, 3, 11, true);
		tripleStore.commit();

		tripleStore.startTransaction();
		tripleStore.removeTriplesByContext(1, 2, 3, 10, true, ignored -> {
		});
		tripleStore.commit();

		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			assertThat(tripleStore.mightMatchBloom(txn, List.of(List.of(predSubject)), 1)).isTrue();
		}

		tripleStore.startTransaction();
		tripleStore.removeTriplesByContext(1, 2, 3, 11, true, ignored -> {
		});
		tripleStore.commit();

		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			assertThat(tripleStore.mightMatchBloom(txn, List.of(List.of(predSubject)), 1)).isFalse();
		}
	}

	@Test
	void typeFiltersTrackSubjectsForRdfTypeObjects() throws Exception {
		Filter personTypeSubject = Filter.typeSubject(true, PERSON_ID);

		tripleStore.startTransaction();
		tripleStore.storeTriple(1, RDF_TYPE_ID, PERSON_ID, 0, true);
		tripleStore.commit();

		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			assertThat(tripleStore.mightMatchBloom(txn, List.of(List.of(personTypeSubject)), 1)).isTrue();
			assertThat(tripleStore.mightMatchBloom(txn, List.of(List.of(personTypeSubject)), 2)).isFalse();
		}
	}

	@Test
	void alignedBulkWritesMaintainBloomFilters() throws Exception {
		Filter predSubject = Filter.predicateSubject(true, 2);
		Filter predObject = Filter.predicateObject(true, 2);

		tripleStore.startTransaction();
		tripleStore.storeTriplesAligned(new long[] { 1, 2 }, new long[] { 2, 2 }, new long[] { 3, 4 },
				new long[] { 0, 0 }, 2, true);
		tripleStore.commit();

		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			assertThat(tripleStore.mightMatchBloom(txn, List.of(List.of(predSubject)), 1)).isTrue();
			assertThat(tripleStore.mightMatchBloom(txn, List.of(List.of(predObject)), 4)).isTrue();
		}
	}

	@Test
	void openingExistingStoreWithBloomEnabledBackfillsFilters() throws Exception {
		File existingStore = new File(dataDir, "existing-store");
		tripleStore.close();
		tripleStore = new TripleStore(existingStore,
				new LmdbStoreConfig("spoc,posc").setBloomFiltersEnabled(false), null);
		tripleStore.startTransaction();
		tripleStore.storeTriple(1, 2, 3, 0, true);
		tripleStore.commit();
		tripleStore.close();

		tripleStore = new TripleStore(existingStore, new LmdbStoreConfig("spoc,posc"), null);

		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			assertThat(tripleStore.mightMatchBloom(txn, List.of(List.of(Filter.predicateSubject(true, 2))), 1))
					.isTrue();
		}
	}

	@Test
	void openingExistingStoreWithDifferentBloomSizingBackfillsFilters() throws Exception {
		File existingStore = new File(dataDir, "resized-existing-store");
		tripleStore.close();
		tripleStore = new TripleStore(existingStore,
				new LmdbStoreConfig("spoc,posc")
						.setBloomFilterExpectedElementsPerFilter(1024)
						.setBloomFilterPartitionCounters(1024),
				null);
		tripleStore.startTransaction();
		for (long subject = 1; subject <= 200; subject++) {
			tripleStore.storeTriple(subject, 2, 3, 0, true);
		}
		tripleStore.commit();
		tripleStore.close();

		tripleStore = new TripleStore(existingStore,
				new LmdbStoreConfig("spoc,posc")
						.setBloomFilterExpectedElementsPerFilter(1024)
						.setBloomFilterPartitionCounters(1),
				null);

		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			Filter filter = Filter.predicateSubject(true, 2);
			for (long subject = 1; subject <= 200; subject++) {
				assertThat(tripleStore.mightMatchBloom(txn, List.of(List.of(filter)), subject))
						.as("subject %s", subject)
						.isTrue();
			}
		}
	}

	@Test
	void configuredFalsePositiveRateControlsFilterSize() throws Exception {
		Field bloomStoreField = TripleStore.class.getDeclaredField("bloomStore");
		bloomStoreField.setAccessible(true);
		Object bloomStore = bloomStoreField.get(tripleStore);

		Field partitionCountField = LmdbCountingBloomStore.class.getDeclaredField("partitionCount");
		partitionCountField.setAccessible(true);

		assertThat(partitionCountField.getInt(bloomStore)).isGreaterThan(1);
	}
}
